import{_ as t,c as a,o,ag as r}from"./chunks/framework.Bw-5EFTY.js";const m=JSON.parse('{"title":"DAG Cost Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/dag-cost/docs/SPEC.md","filePath":"packages/dag-cost/docs/SPEC.md"}'),i={name:"packages/dag-cost/docs/SPEC.md"};function d(s,e,c,l,n,u){return o(),a("div",null,e[0]||(e[0]=[r('<h1 id="dag-cost-specification" tabindex="-1">DAG Cost Specification <a class="header-anchor" href="#dag-cost-specification" aria-label="Permalink to &quot;DAG Cost Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p><code>@robota-sdk/dag-cost</code> provides cost evaluation services for DAG orchestration using CEL (Common Expression Language) formulas. It defines the cost metadata model and a storage port interface, enabling cost estimation and calculation for DAG node executions.</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li><strong>CEL evaluation only.</strong> Cost computation is delegated to CEL formula evaluation; no hardcoded pricing logic.</li><li><strong>No persistence.</strong> This package defines the storage port interface (<code>ICostMetaStoragePort</code>) but does not implement it. Adapter packages provide concrete implementations.</li><li><strong>No domain logic beyond cost.</strong> This package does not manage DAG execution, scheduling, or node lifecycle.</li><li><strong>Result-based error handling.</strong> All evaluator methods return <code>TResult</code> — no thrown exceptions cross the public API boundary.</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dependency</th><th>Purpose</th></tr></thead><tbody><tr><td><code>@marcbachmann/cel-js</code></td><td>CEL expression parsing and evaluation</td></tr><tr><td><code>@robota-sdk/dag-core</code></td><td><code>TResult</code> and <code>IDagError</code> types for structured error handling</td></tr></tbody></table><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>CelCostEvaluator</code></td><td>Class</td><td>Evaluates and validates CEL cost formulas against variable contexts</td></tr><tr><td><code>ICostMeta</code></td><td>Interface</td><td>Cost metadata for a node type (formula, category, variables, enabled flag)</td></tr><tr><td><code>TCostMetaCategory</code></td><td>Type</td><td>Union of cost categories: <code>&#39;ai-inference&#39; | &#39;transform&#39; | &#39;io&#39; | &#39;custom&#39;</code></td></tr><tr><td><code>ICostMetaStoragePort</code></td><td>Interface</td><td>Port for CRUD operations on cost metadata (get, getAll, save, delete)</td></tr></tbody></table><h2 id="key-behaviors" tabindex="-1">Key Behaviors <a class="header-anchor" href="#key-behaviors" aria-label="Permalink to &quot;Key Behaviors&quot;">​</a></h2><h3 id="celcostevaluator" tabindex="-1">CelCostEvaluator <a class="header-anchor" href="#celcostevaluator" aria-label="Permalink to &quot;CelCostEvaluator&quot;">​</a></h3><ul><li><code>evaluate(formula, context)</code> — Evaluates a CEL formula with the given variable bindings. Returns <code>TResult&lt;number, IDagError&gt;</code>. BigInt results are coerced to finite numbers.</li><li><code>validate(formula)</code> — Parses a CEL formula without evaluation to check syntax. Returns <code>TResult&lt;void, IDagError&gt;</code>.</li><li>Error codes: <code>CEL_EVAL_ERROR</code> (runtime failure), <code>CEL_PARSE_ERROR</code> (syntax error), <code>CEL_NON_NUMERIC</code> (non-numeric result).</li></ul><h3 id="icostmeta" tabindex="-1">ICostMeta <a class="header-anchor" href="#icostmeta" aria-label="Permalink to &quot;ICostMeta&quot;">​</a></h3><p>Each cost metadata entry contains:</p><ul><li><code>nodeType</code> — identifier for the node type</li><li><code>displayName</code> — human-readable name</li><li><code>category</code> — one of the <code>TCostMetaCategory</code> values</li><li><code>estimateFormula</code> — CEL formula for cost estimation (required)</li><li><code>calculateFormula</code> — CEL formula for actual cost calculation (optional)</li><li><code>variables</code> — default variable bindings for the formulas</li><li><code>enabled</code> / <code>updatedAt</code> — lifecycle fields</li></ul><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><ul><li><strong>Cost estimation:</strong> Compute estimated costs before executing a DAG run.</li><li><strong>Cost calculation:</strong> Compute actual costs after execution using runtime variables.</li><li><strong>Formula validation:</strong> Verify formula syntax at design time in the DAG designer.</li></ul><h2 id="future-direction" tabindex="-1">Future Direction <a class="header-anchor" href="#future-direction" aria-label="Permalink to &quot;Future Direction&quot;">​</a></h2><ul><li>Additional evaluator backends beyond CEL (e.g., simple arithmetic DSL).</li><li>Cost aggregation utilities for multi-node DAG runs.</li></ul>',19)]))}const f=t(i,[["render",d]]);export{m as __pageData,f as default};
